import tensorflow as tf
from flask import Flask, request, jsonify
import os

app = Flask(__name__)

# Model configuration
model = tf.keras.Sequential([
    tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(28, 28, 1)),
    tf.keras.layers.MaxPooling2D((2, 2)),
    tf.keras.layers.Flatten(),
    tf.keras.layers.Dense(64, activation='relu'),
    tf.keras.layers.Dense(10)
])

model.compile(optimizer='adam',
              loss=tf.keras.losses.SparseCategoricalCrossentropy(from_logits=True),
              metrics=['accuracy'])

# Load existing model if available
if os.path.exists('model.h5'):
    model.load_weights('model.h5')

@app.route('/train', methods=['POST'])
def train():
    file = request.files['file']
    if file and file.filename.endswith('.csv'):
        # Process CSV file (assuming it contains image data)
        # For simplicity, let's assume the CSV is preprocessed into a numpy array
        import pandas as pd
        import numpy as np
        data = pd.read_csv(file.stream).values
        images = data[:, :-1].reshape(-1, 28, 28, 1) / 255.0  # Normalize images
        labels = data[:, -1]

        # Train the model
        model.fit(images, labels, epochs=1)

        # Save the updated model
        model.save('model.h5')

        return jsonify({'status': 'success', 'message': 'Model trained successfully'})
    else:
        return jsonify({'status': 'error', 'message': 'Invalid file format'})

if __name__ == '__main__':
    app.run(debug=True)